external_knowledge:
- "captains" metaphorically represents users;
- "uncharted waters" symbolizes notifications that have not been read (is_read = 0);
- "messages awaiting their attention" refers to unread notifications (COUNT(DISTINCT n.notification_id) >= 5);
- "voyages charted" metaphorically refers to reviews created by users (COUNT(DISTINCT r.review_id) > 2).

sql:
SELECT COUNT(DISTINCT film_id) 
FROM (
    SELECT film_id FROM reviews
    UNION
    SELECT film_id FROM votes
);

SELECT AVG(rating) 
FROM films 
WHERE director = 'Lee Tamahori';

SELECT AVG(rating) AS average_rating
FROM films
WHERE director = '<director_name>';

SELECT f.title, f.director, IFNULL(r.rating, 0) AS rating
FROM films f
LEFT JOIN reviews r ON f.film_id = r.film_id;

SELECT user_id, COUNT(film_id) AS Num_Films_Rated 
FROM user_ratings 
GROUP BY user_id;

SELECT COUNT(user_rating_id) 
FROM user_ratings 
WHERE film_id = (SELECT film_id FROM films WHERE title = 'Film Title');

SELECT title
FROM films
WHERE rating > (SELECT AVG(rating) FROM films);

SELECT users.username, reviews.review_text
FROM users
INNER JOIN reviews ON users.user_id = reviews.user_id;

SELECT AVG(rating) AS average_rating
FROM films
WHERE director = 'James Cameron';
